def binary_search(arr, target):
    left, right = 0, len(arr) - 1  # Set right to the last valid index

    while left <= right:  # Use left <= right for inclusive boundary search
        mid = (left + right) // 2

        if arr[mid] == target:
            return mid
        elif arr[mid] < target:
            left = mid + 1  # Move the left boundary past mid
        else:
            right = mid - 1 # Move the right boundary before mid

    return -1

